<x-storefront.account.orders.page :seo="$seo" :account="$account" :navigation="$navigation" title="Return Details & Status" :subtitle="'Track '.$returnRequest->return_number.' from request review through item receipt, inspection, replacement, refund, or final resolution.'" eyebrow="Return status">
    <x-slot:actions><a class="btn btn-white" href="{{ route('account.returns.index') }}">Return History</a></x-slot:actions>
