black">Request Summary</h3><div class="mt-4 grid gap-4 text-sm"><div><span class="block text-xs font-black uppercase text-slate-400">Reason</span><strong>{{ str($returnRequest->reason_code)->headline() }}</strong></div><div><span class="block text-xs font-black uppercase text-slate-400">Requested resolution</span><strong>{{ str($returnRequest->requested_resolution)->headline() }}</strong></div><div><span class="block text-xs font-black uppercase text-slate-400">Approved amount</span><strong>{{ $returnRequest->approved_amount !== null ? '$'.number_format((float)$returnRequest->approved_amount,2) : 'Pending' }}</strong></div></div>@foreach($returnRequest->refunds as $refund)<a class="btn btn-red mt-5 w-full" href="{{ route('account.refunds.show',$refund) }}">View Refund Status</a>@endforeach</aside></div>
